  window.DENO_DOC_SEARCH_INDEX = {"kind":"search","nodes":[{"id":"namespace_ethertype_ipv4","kind":[{"char":"v","kind":"Variable","title":"Variable"}],"name":"ETHERTYPE_IPV4","file":".","doc":"EtherType for IPv4.","url":"././~/ETHERTYPE_IPV4.html","deprecated":false},{"id":"namespace_ethertype_arp","kind":[{"char":"v","kind":"Variable","title":"Variable"}],"name":"ETHERTYPE_ARP","file":".","doc":"EtherType for ARP.","url":"././~/ETHERTYPE_ARP.html","deprecated":false},{"id":"namespace_ip_protocol_icmp","kind":[{"char":"v","kind":"Variable","title":"Variable"}],"name":"IP_PROTOCOL_ICMP","file":".","doc":"IPv4 protocol number for ICMP.","url":"././~/IP_PROTOCOL_ICMP.html","deprecated":false},{"id":"namespace_ip_protocol_udp","kind":[{"char":"v","kind":"Variable","title":"Variable"}],"name":"IP_PROTOCOL_UDP","file":".","doc":"IPv4 protocol number for UDP.","url":"././~/IP_PROTOCOL_UDP.html","deprecated":false},{"id":"namespace_l4payload","kind":[{"char":"T","kind":"TypeAlias","title":"Type Alias"}],"name":"L4Payload","file":".","doc":"Decoded transport-layer payload of an IPv4 datagram.kind discriminates the typed branches; an unknown protocol surfaces as the raw Uint8Array payload for the caller to dispatch further.","url":"././~/L4Payload.html","deprecated":false},{"id":"namespace_ipv4decoded","kind":[{"char":"T","kind":"TypeAlias","title":"Type Alias"}],"name":"Ipv4Decoded","file":".","doc":"Decoded IPv4 datagram: header fields plus a structured payload for the carried L4 protocol.","url":"././~/Ipv4Decoded.html","deprecated":false},{"id":"namespace_ethernetpayload","kind":[{"char":"T","kind":"TypeAlias","title":"Type Alias"}],"name":"EthernetPayload","file":".","doc":"Decoded network-layer payload of an Ethernet II frame.kind discriminates the typed branches; an unknown EtherType surfaces as the raw Uint8Array payload.","url":"././~/EthernetPayload.html","deprecated":false},{"id":"namespace_framedecoded","kind":[{"char":"T","kind":"TypeAlias","title":"Type Alias"}],"name":"FrameDecoded","file":".","doc":"Decoded Ethernet II frame: same fields as Ethernet2Frame, but payload is the structured EthernetPayload instead of raw bytes.","url":"././~/FrameDecoded.html","deprecated":false},{"id":"namespace_inetcoder","kind":[{"char":"f","kind":"Function","title":"Function"}],"name":"inetCoder","file":".","doc":"Creates a coder for an Ethernet II frame whose payload is recursively unpacked into typed network/transport-layer values.The shape mirrors physical layout: each layer's payload field is the decoded next layer (a discriminated union) rather than raw bytes. Layers the family doesn't have a coder for default to Uint8Array, so this coder is safe to point at arbitrary captured traffic.","url":"././~/inetCoder.html","deprecated":false},{"id":"namespace_internetchecksum","kind":[{"char":"f","kind":"Function","title":"Function"}],"name":"internetChecksum","file":".","doc":"Computes the 16-bit Internet checksum (RFC 1071) over a span of bytes.The checksum is the 16-bit one's complement of the one's complement sum of all 16-bit words in the span. If the byte length is odd, the trailing byte is padded with zero for the purposes of the sum.Callers typically zero out the checksum field of a header before computing, then write the returned value back into that field. A subsequent call over the completed packet returns 0, the standard receiver-side verification.The function is layout-agnostic — it operates on whatever bytes are passed in. For protocols that include a pseudo-header in the checksum (UDP, TCP), the caller is responsible for assembling the pseudo-header followed by the datagram and passing the concatenation.","url":"././~/internetChecksum.html","deprecated":false}]};
